        VALUES(v_var_id,'Band Pallof Press','beginner','isolation','push',false,false,'low',false,
            NULL,'public','active',jsonb_build_object('it',jsonb_build_object('name','Pallof Press con Elastico','description','Variante di Pallof Press - Core in rotazione o anti-rotazione: mantieni colonna lunga e bacino controllato, muovi dal tronco senza perdere brace. Usa un carico gestibile e lavora in controllo.'),
